function techIcon(name: string) {
  const normalized = name.toLowerCase();

  if (normalized.includes("drone") || normalized.includes("ros")) {
    return <CircuitBoard className="h-3.5 w-3.5" />;
  }

  if (normalized.includes("ml") || normalized.includes("torch") || normalized.includes("onnx")) {
    return <Cpu className="h-3.5 w-3.5" />;
  }

  return <Code2 className="h-3.5 w-3.5" />;
}

