import * as React from "react";

type CardProps = React.HTMLAttributes<HTMLDivElement>;

export function Card({ className = "", ...props }: CardProps) {
  return (
    <div
      className={[
        "group rounded-2xl border border-border/70 bg-card/90 shadow-sm backdrop-blur-sm transition-all",
        "hover:-translate-y-0.5 hover:shadow-lg hover:shadow-border/40",
        className,
      ]
        .filter(Boolean)
        .join(" ")}
      {...props}
    />
  );
}

export function CardHeader({
  className = "",
  ...props
}: CardProps & { children?: React.ReactNode }) {
  return (
    <div
      className={["px-6 pt-5 pb-3 flex flex-col gap-1", className]
        .filter(Boolean)
        .join(" ")}
      {...props}
    />
  );
}

export function CardTitle({
  className = "",
  ...props
}: CardProps & { children?: React.ReactNode }) {
  return (
    <h3
      className={["text-base font-semibold tracking-tight", className]
        .filter(Boolean)
        .join(" ")}
      {...props}
    />
  );
}

export function CardDescription({
  className = "",
  ...props
}: CardProps & { children?: React.ReactNode }) {
  return (
    <p
      className={["text-sm text-muted-foreground", className]
        .filter(Boolean)
        .join(" ")}
      {...props}
    />
  );
}

export function CardContent({
  className = "",
  ...props
}: CardProps & { children?: React.ReactNode }) {
  return (
    <div
      className={["px-6 pb-5 pt-1 flex flex-col gap-3", className]
        .filter(Boolean)
        .join(" ")}
      {...props}
    />
  );
}

